-- INIT NEW NUMERIC COLUMNS
UPDATE PSP_QBDT_PAYROLL_ITEM_INFO
SET TOKEN = -1
WHERE TOKEN IS NULL;

UPDATE PSP_QBDT_EMPLOYEE_INFO
SET TOKEN = -1
WHERE TOKEN IS NULL;

UPDATE PSP_QBDT_PAYCHECK_INFO 
SET TOKEN = -2
WHERE TOKEN IS NULL;

UPDATE PSP_QBDT_TRANSACTION_INFO 
SET TOKEN = -2
WHERE TOKEN IS NULL;

-- INIT NEW COMPANY FKS
UPDATE PSP_QBDT_PAYROLL_ITEM_INFO
SET COMPANY_FK = (SELECT COMPANY_FK 
                  FROM PSP_COMPANY_PAYROLL_ITEM
                  WHERE COMPANY_PAYROLL_ITEM_SEQ = COMPANY_PAYROLL_ITEM_FK)
WHERE COMPANY_PAYROLL_ITEM_FK IS NOT NULL
	AND COMPANY_FK IS NULL;

UPDATE PSP_QBDT_PAYROLL_ITEM_INFO
SET COMPANY_FK = (SELECT COMPANY_FK 
                  FROM PSP_COMPANY_LAW
                  JOIN PSP_COMPANY_AGENCY ON COMPANY_AGENCY_FK = COMPANY_AGENCY_SEQ
                  WHERE COMPANY_LAW_SEQ = COMPANY_LAW_FK)
WHERE COMPANY_LAW_FK IS NOT NULL
	AND COMPANY_FK IS NULL;

UPDATE PSP_QBDT_EMPLOYEE_INFO
SET COMPANY_FK = (SELECT COMPANY_FK 
                  FROM PSP_EMPLOYEE                  
                  WHERE EMPLOYEE_SEQ = EMPLOYEE_FK)
WHERE EMPLOYEE_FK IS NOT NULL
	AND COMPANY_FK IS NULL;

UPDATE PSP_TAX_TABLE_MISC_DATA TMD
SET COMPANY_FK = (SELECT COMPANY_FK 
                  FROM PSP_EMPLOYEE
				  JOIN PSP_EMPLOYEE_TAX ON EMPLOYEE_FK = EMPLOYEE_SEQ				  
                  WHERE EMPLOYEE_TAX_SEQ = TMD.EMPLOYEE_TAX_FK)
WHERE EMPLOYEE_TAX_FK IS NOT NULL
	AND COMPANY_FK IS NULL;

-- MIGRATE COMPANY DATA INTO QB INFO
INSERT INTO PSP_QUICKBOOKS_INFO
(SELECT 
 FN_FORMAT_SYSGUID(SYS_GUID()), 0, 'znorcross', SYS_EXTRACT_UTC(systimestamp), 'znorcross', SYS_EXTRACT_UTC(systimestamp), -1,
 AGREE_INFO_AGREE_CREATE_DATE, QB_INFO_APP_VERSION, QUICKBOOKS_INFO_APPLICATION_ID, QUICKBOOKS_INFO_LICENSE_NUMBER, QB_INFO_COA_FEE_ACC_NAME, QB_INFO_COA_SALES_TAX_ACC_NAME, QUICKBOOKS_INFO_TAX_TABLE_ID, QB_INFO_AS400_PAYROLL_COUNT,
 AGREEMENT_INFO_SERVICE_TYPE, AGREE_INFO_SUB_NBR, -1, AGREE_INFO_AGREE_SUB_TYPE, AGREEMENT_INFO_NAME, AGREEMENT_INFO_SERVICE_KEY, AGREE_INFO_SOURCE_ID, COMPANY_SEQ
 FROM PSP_COMPANY);
 
-- UPDATE PROPERTY AUDITS
UPDATE PSP_PROPERTY_AUDIT
SET CLASS_NAME = 'QuickbooksInfo', PROPERTY_NAME = replace(PROPERTY_NAME, 'QuickbooksInfo.') 
WHERE CLASS_NAME = 'Company' AND PROPERTY_NAME LIKE 'QuickbooksInfo%';

UPDATE PSP_PROPERTY_AUDIT
SET CLASS_NAME = 'QuickbooksInfo', PROPERTY_NAME = replace(PROPERTY_NAME, 'AgreementInfo.') 
WHERE CLASS_NAME = 'Company' AND PROPERTY_NAME LIKE 'AgreementInfo%' ;

